// قراءة قائمة الملفات من File API ثم قراءة كل ملف واستخراج الروابط
const FILE_API = 'http://host.docker.internal:8765';
const INBOX_PATH = 'D:\\SaleHSaaS3\\url_inbox';

let listResponse;
try {
  listResponse = await $helpers.httpRequest({
    method: 'GET',
    url: FILE_API + '/list',
    qs: { path: INBOX_PATH, extensions: '.txt,.url,.md' }
  });
} catch(e) {
  return [{ json: { skip: true, error: 'File API غير متاح: ' + e.message } }];
}

const files = listResponse.files || [];
if (files.length === 0) {
  return [{ json: { skip: true, message: 'لا توجد ملفات في url_inbox' } }];
}

const results = [];
for (const file of files) {
  const fileName = file.fileName;
  const filePath = file.filePath;
  let readResponse;
  try {
    readResponse = await $helpers.httpRequest({
      method: 'GET',
      url: FILE_API + '/read',
      qs: { path: filePath }
    });
  } catch(e) {
    continue;
  }
  const content = readResponse.content || '';
  const lines = content.split('\n').map(function(l) { return l.trim(); }).filter(function(l) { return l.length > 0; });
  const urls = lines.filter(function(l) { return l.startsWith('http://') || l.startsWith('https://'); });
  if (urls.length === 0) continue;
  const title = fileName.replace(/\.(txt|url|md)$/i, '').replace(/[_-]/g, ' ');
  for (let i = 0; i < urls.length; i++) {
    results.push({
      json: {
        url: urls[i],
        title: urls.length > 1 ? title + ' (' + (i + 1) + ')' : title,
        fileName: fileName,
        filePath: filePath,
        totalUrls: urls.length
      }
    });
  }
}

if (results.length === 0) {
  return [{ json: { skip: true, message: 'لا توجد روابط صالحة في أي ملف' } }];
}

return results;

const inputData = $input.first().json;
if (inputData.skip || !inputData.url) {
  return [{ json: { skip: true, reason: 'لا يوجد رابط' } }];
}
const url = inputData.url;
const title = inputData.title || '';
let type = 'webpage';
if (url.indexOf('youtube.com') !== -1 || url.indexOf('youtu.be') !== -1) type = 'youtube';
else if (url.indexOf('twitter.com') !== -1 || url.indexOf('x.com') !== -1) type = 'twitter';
else if (url.indexOf('linkedin.com') !== -1) type = 'linkedin';
else if (url.indexOf('facebook.com') !== -1 || url.indexOf('fb.com') !== -1) type = 'facebook';
else if (url.indexOf('instagram.com') !== -1) type = 'instagram';
else if (url.indexOf('tiktok.com') !== -1) type = 'tiktok';
else if (url.indexOf('reddit.com') !== -1) type = 'reddit';
else if (/\.(mp3|wav|ogg|m4a|aac)$/i.test(url)) type = 'audio';
else if (/\.(mp4|avi|mov|mkv|webm)$/i.test(url)) type = 'video';
else if (/\.pdf$/i.test(url)) type = 'pdf';
const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
const safeTitle = (title || type).replace(/[^\u0600-\u06FFa-zA-Z0-9 ]/g, '').trim().slice(0, 50);
const outputFilename = timestamp + '_' + safeTitle + '.md';
return [{ json: Object.assign({}, inputData, { type: type, outputFilename: outputFilename, timestamp: timestamp }) }];

// استدعاء Ollama عبر helpers.httpRequest لتجنب مشاكل JSON في n8n
const typeData = $('🔍 تحديد نوع الرابط').first().json;
const jinaData = $input.first().json;
const content = jinaData.body || jinaData.data || '';
const contentSlice = content.slice(0, 3000);
const prompt = 'أنت مساعد متخصص في تلخيص المحتوى. المصدر: ' + typeData.url + '\n\nالمهمة:\n1. اكتب ملخصاً موجزاً (3-5 أسطر)\n2. استخرج 5-7 نقاط رئيسية\n3. حدد الكلمات المفتاحية\n\nالمحتوى:\n' + contentSlice + '\n\nأجب بالعربية بصيغة Markdown.';
let summary = '';
try {
  const ollamaResponse = await $helpers.httpRequest({
    method: 'POST',
    url: 'http://host.docker.internal:11434/api/generate',
    body: {
      model: 'qwen2.5:3b',
      prompt: prompt,
      stream: false,
      options: { temperature: 0.3, num_predict: 800 }
    },
    json: true,
    timeout: 120000
  });
  summary = ollamaResponse.response || '';
} catch(e) {
  summary = '(فشل التلخيص: ' + e.message + ')';
}
return [{ json: { jinaContent: content, summary: summary } }];

const FILE_API = 'http://host.docker.internal:8765';
const data = $input.first().json;
const markdown = data.markdown;
const outputFilename = data.outputFilename;
const filePath = data.filePath;
const fileName = data.fileName;

try {
  await $helpers.httpRequest({
    method: 'POST',
    url: FILE_API + '/write',
    body: {
      path: 'D:\\SaleHSaaS3\\knowledge_inbox\\' + outputFilename,
      content: markdown
    },
    json: true
  });
} catch(e) {
  throw new Error('فشل حفظ ملف Markdown: ' + e.message);
}

try {
  await $helpers.httpRequest({
    method: 'POST',
    url: FILE_API + '/move',
    body: {
      source: filePath,
      destination: 'D:\\SaleHSaaS3\\url_processed\\' + fileName
    },
    json: true
  });
} catch(e) {
  console.log('تحذير: فشل نقل الملف: ' + e.message);
}

return [{ json: Object.assign({}, data, {
  savedTo: 'D:\\SaleHSaaS3\\knowledge_inbox\\' + outputFilename,
  movedFrom: filePath,
  success: true
}) }];

